from itertools import permutations

class Solution:
    def maxGoodNumber(self, nums):
        best = 0
        for perm in permutations(nums):
            s = ''.join(format(x, 'b') for x in perm)
            best = max(best, int(s, 2))
        return best

solutions.python:
from functools import cmp_to_key

class Solution:
    def maxGoodNumber(self, nums):
        bins = [format(x, 'b') for x in nums]

        def cmp(a, b):
            ab = int(a + b, 2)
            ba = int(b + a, 2)
            if ab > ba:
                return -1
            if ab < ba:
                return 1
            return 0

        bins.sort(key=cmp_to_key(cmp))
        return int(''.join(bins), 2)

