var maxGoodNumber = function(nums) {
    const bins = nums.map(x => x.toString(2));
    bins.sort((a, b) => {
        const ab = parseInt(a + b, 2);
        const ba = parseInt(b + a, 2);
        return ba - ab;
    });
    return parseInt(bins.join(''), 2);
};
